create table account_roles (account_id bigint not null, role_id bigint not null, primary key (account_id, role_id));
create table accounts (created_at timestamp(6) with time zone, id bigint generated by default as identity, updated_at timestamp(6) with time zone, email varchar(255) unique, password varchar(255), username varchar(255) unique, primary key (id));
create table admin_settings (email_confirmation boolean not null, inventory_alerts boolean not null, order_alerts boolean not null, session_timeout_minutes integer not null, created_at timestamp(6) with time zone, id bigint generated by default as identity, updated_at timestamp(6) with time zone, primary key (id));
create table admins (require_login_email_confirmation boolean, id_account bigint not null, display_name varchar(255), role_title varchar(255), user_status varchar(64), primary key (id_account));
create table blogs (is_deleted boolean, show_on_homepage boolean, created_at timestamp(6) with time zone, id bigint generated by default as identity, id_category_blog bigint, updated_at timestamp(6) with time zone, description text, title varchar(255), image jsonb, introduction jsonb, status varchar(64), primary key (id));
create table bulk_discounts (discount_percent numeric(38,2), max_quantity integer, min_quantity integer, created_at timestamp(6) with time zone, id bigint generated by default as identity, id_product bigint, updated_at timestamp(6) with time zone, label varchar(255), range_label varchar(255), status varchar(64), primary key (id));
create table category_blogs (id bigint generated by default as identity, name varchar(255), primary key (id));
create table customers (id_account bigint not null, avatar_url varchar(2000), full_name varchar(255), phone varchar(255) unique, primary key (id_account));
create table dealer_cart_items (quantity integer, created_at timestamp(6) with time zone, id_dealer bigint not null, id_product_of_cart bigint not null, updated_at timestamp(6) with time zone, primary key (id_dealer, id_product_of_cart));
create table dealer_support_tickets (closed_at timestamp(6) with time zone, created_at timestamp(6) with time zone, dealer_id bigint not null, id bigint generated by default as identity, resolved_at timestamp(6) with time zone, updated_at timestamp(6) with time zone, admin_reply text, message text not null, subject varchar(255) not null, ticket_code varchar(255) not null unique, category varchar(64) not null, priority varchar(64) not null, status varchar(64) not null, primary key (id));
create table dealers (credit_limit numeric(38,2), id_account bigint not null, avatar_url varchar(2000), sales_policy varchar(4000), address_line varchar(255), business_name varchar(255), city varchar(255), contact_name varchar(255), country varchar(255), district varchar(255), phone varchar(255) unique, tax_code varchar(255) unique, ward varchar(255), customer_status varchar(64), customer_tier varchar(64), primary key (id_account));
create table notifies (is_read boolean, created_at timestamp(6) with time zone, id bigint generated by default as identity, id_account bigint, read_at timestamp(6) with time zone, content text, link varchar(255), title varchar(255), type varchar(64), primary key (id));
create table order_items (quantity integer, unit_price numeric(38,2), id bigint generated by default as identity, id_order bigint, id_product bigint, primary key (id));
create table orders (is_deleted boolean, paid_amount numeric(38,2), shipping_fee integer, created_at timestamp(6) with time zone, id bigint generated by default as identity, id_dealer bigint, updated_at timestamp(6) with time zone, note text, order_code varchar(255) unique, receiver_address varchar(255), receiver_name varchar(255), receiver_phone varchar(255), payment_method varchar(64), payment_status varchar(64), status varchar(64), primary key (id));
create table password_reset_tokens (account_id bigint not null, created_at timestamp(6) with time zone, expires_at timestamp(6) with time zone not null, id bigint generated by default as identity, token varchar(120) not null unique, primary key (id));
create table payments (amount numeric(38,2), created_at timestamp(6) with time zone, id bigint generated by default as identity, id_order bigint, paid_at timestamp(6) with time zone, channel varchar(255), note text, proof_file_name varchar(255), transaction_code varchar(255) unique, method varchar(64), status varchar(64), primary key (id));
create table product_of_carts (price_snapshot numeric(38,2), id bigint generated by default as identity, id_product bigint, note varchar(255), primary key (id));
create table product_serials (id bigint generated by default as identity, id_customer bigint, id_dealer bigint, id_order bigint, id_product bigint, imported_at timestamp(6) with time zone, serial varchar(255) unique, warehouse_id varchar(255), warehouse_name varchar(255), status varchar(64), primary key (id));
create table products (is_deleted boolean, is_featured boolean, retail_price numeric(38,2), show_on_homepage boolean, stock integer, warranty_period integer, created_at timestamp(6) with time zone, id bigint generated by default as identity, updated_at timestamp(6) with time zone, name varchar(255), short_description varchar(255), sku varchar(255) unique, descriptions jsonb, image jsonb, publish_status varchar(64), specifications jsonb, videos jsonb, primary key (id));
create table roles (id bigint generated by default as identity, description varchar(255), name varchar(255) unique, primary key (id));
create table warranties (created_at timestamp(6) with time zone, id bigint generated by default as identity, id_customer bigint, id_dealer bigint, id_order bigint, id_product_serial bigint unique, purchase_date timestamp(6) with time zone, updated_at timestamp(6) with time zone, warranty_end timestamp(6) with time zone, warranty_start timestamp(6) with time zone, customer_address varchar(255), customer_email varchar(255), customer_name varchar(255), customer_phone varchar(255), warranty_code varchar(255) unique, status varchar(64), primary key (id));
